import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"秃鹰战车","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/秃鹰战车.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/秃鹰战车.md"}'),o={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/秃鹰战车.md"};function d(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"秃鹰战车",tabindex:"-1"},[n("秃鹰战车 "),r("a",{class:"header-anchor",href:"#秃鹰战车","aria-label":'Permalink to "秃鹰战车"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),s('<h1 id="秃鹰战车-1" tabindex="-1">秃鹰战车 <a class="header-anchor" href="#秃鹰战车-1" aria-label="Permalink to &quot;秃鹰战车&quot;">​</a></h1><p>（出自星际争霸）<br> 秃鹰战车<br> 价格：D+500<br> “秃鹰战车主要担任侦察和巡逻任务，它所装备的两台大型火力发动机在极限状态下能令其以230英里每小时的速度狂飙，但其的敞开式驾驶舱又很好的克制了驾驶员狂飙。”</p><p>类别：轻型载具<br> 体积：8<br> 结构值：22<br> 装甲：6<br> 速度：基础80，加速度40，最高160（均已计算加成）<br> 载员：驾驶员1<br> 特性：悬浮车体、离子推进器</p><p>【重力悬浮】：秃鹰战车以其的高机动性和高通过性在早期得到了泰伦军方的采用，虽然随着技术更迭其缺乏防护的缺点越来越明显，但不乏有的势力依旧装备了些许。<br> 由于其采用的悬浮车体，秃鹰战车可以轻松的通过大部分地形，这视为一个免疫C级困难地形的能力。</p><p>【离子推进器】：秃鹰战车傲人的动力系统，配合其的悬浮车体能够轻松跑出远超恶火战车的时速和机动性。如果你够胆的话，把秃鹰当机车开也不是不行。<br> 当你驾驶秃鹫战车时，你获得2点闪避防御。</p><p>===【下属武器】===<br> 破片榴弹发射器<br> 价格：D+500<br> 秃鹰战车配备的一对车载武器，平时收纳隐藏在车头中，需要时会展开盖板方便发射榴弹。</p><p>武器伤害：8L<br> 武器特性：【高速5】【破甲3】<br> 伤害类型：物理-穿刺<br> 射程：200<br> 装弹数：1</p><p>【破片榴弹】：秃鹰战车装配的榴弹威力十足，甚至足矣重创自身。使用本武器攻击时获得1点附加成功。</p><p>【备弹充足】：考虑到轮回者没有战地补给的机会，主神因此在车体内准备了充足的弹药，视为其拥有【无限子弹】特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
